@Test
public void testEscapedDigit() throws Exception {
    final Lexer lexer = getLexer("value\\1test", formatWithEscaping);
    assertThat(lexer.nextToken(new Token()), hasContent("value\\1test"));
}

@Test
public void testEscapedSpecialChar() throws Exception {
    final Lexer lexer = getLexer("data\\@symbol", formatWithEscaping);
    assertThat(lexer.nextToken(new Token()), hasContent("data\\@symbol"));
}

@Test
public void testBackslashEscapingWithUnknownChar() throws IOException {
    final String code = "value\\xtest";
    final CSVFormat format = CSVFormat.newBuilder(',').withEscape('\\').build();
    final CSVParser parser = new CSVParser(code, format);
    final List<CSVRecord> records = parser.getRecords();
    assertEquals(1, records.size());
    assertEquals("value\\xtest", records.get(0).get(0));
}
